import React from "react";
import ExpenseItem from "./ExpenseItem";

const Expenses = ({ items }) => {
  return (
    <div>
      <ExpenseItem
        title={it[0].title}
        amount={it[0].amount}
        date={it[0].date}
      />
      <ExpenseItem
        title={it[1].title}
        amount={it[1].amount}
        date={it[1].date}
      />
      <ExpenseItem
        title={it[2].title}
        amount={it[2].amount}
        date={it[2].date}
      />
      <ExpenseItem
        title={it[3].title}
        amount={it[3].amount}
        date={it[3].date}
      />
    </div>
  );
};

export default Expenses;
